input_num = int(input().split('
')[0])
nums = list(map(int, input().split('
')[1].split(' ')))

class Solution:
    def solve(self, nums:
            list[int]) -> bool:
        n = len(nums)
        for i in range(n):
            val = nums[i]
            parent = (i-1)//2
            if parent >= 0:
                if nums[parent] >= val:
                    continue
                else:
                    nums[parent] = val
        return True

solution = Solution()
print(solution.solve(nums))

