#include <iostream>
#include <vector>
using namespace std;

class Solution {
public: bool solve(vector<int>& nums) {
    int n = nums.size();
    for (int i = 0; i < n; i++) {
        int val = nums[i];
        int parent = (i-1)/2;
        if (parent >= 0) {
            if (nums[parent] >= val) {
                continue;
            } else {
                nums[parent] = val;
            }
        }
    }
    return true;
}
};

